module register10(
	input wire clk,
	input wire rst,
	input wire en,
	input wire [9:0] D,
	output reg [9:0] Q
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
	if (rst)
		Q <= 10'b0000000000;
	else if (en)
		Q <= D;
end
endmodule
